import re
from openai_agents import Agent

def pii_guardrail_filter(content: str) -> str:
    replacements = {
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': '[EMAIL]',
        r'\b\d{3}-\d{2}-\d{4}\b': '[SSN]',
        r'\b\d{3}[\s\-]?\d{3}[\s\-]?\d{4}\b': '[PHONE]'
    }
    filtered = content
    for pattern, replacement in replacements.items():
        filtered = re.sub(pattern, replacement, filtered)
    return filtered

class SafeAgent(Agent):
    def _process_output(self, output):
        return pii_guardrail_filter(output)

from functools import wraps
from openai_agents import tool

def sanitize_pii_output(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        import re
        result = re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL]', result)
        result = re.sub(r'\b\d{3}-\d{2}-\d{4}\b', '[SSN]', result)
        return result
    return wrapper

@sanitize_pii_output
@tool
def get_customer_info(customer_id: str):
    return f'Customer john@example.com, SSN 123-45-6789'

